package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testGetQuoteMode() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;
        CSVFormat csvFormat = new CSVFormat(',', '"', expectedQuoteMode, '#', '\\', true, false, "\r\n",
                "\\N", new Object[]{"Header"}, new String[]{"Name", "Age"}, true, false, true, false, true);

        // When
        QuoteMode actualQuoteMode = csvFormat.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }
}
